-- 1. Holiday Lets x Web Design
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'holiday-lets',
  'web-design',
  'Holiday let owners pay significant commission to Airbnb, Booking.com, and Vrbo for every booking, typically fifteen to twenty percent of the total stay value. A purpose-built direct booking website reduces your dependency on these platforms by giving guests a commission-free way to book directly, while also providing the professional online presence that reassures potential guests your property is legitimate, well-managed, and as beautiful as the photos suggest. Your website must showcase your property with full-screen photography, virtual tours, and detailed room-by-room descriptions. It needs a real-time availability calendar synced with your channel manager, a secure direct booking system with integrated payment processing, and compelling local area content highlighting nearby beaches, countryside walks, historic towns, and restaurants that makes guests excited about the destination as much as the property. Most holiday let websites are basic templates that look identical to every other cottage rental page. We build bespoke direct booking websites that capture the unique character of your Kent holiday property, whether it is a coastal retreat in Whitstable, a countryside barn conversion near Canterbury, or a historic townhouse in Rye.',
  'Every booking through Airbnb or Booking.com costs you fifteen to twenty percent in commission. A property earning forty thousand pounds per year through platforms loses six to eight thousand pounds in commission fees alone. A direct booking website that captures even thirty percent of your bookings saves thousands annually while giving you full control over the guest relationship, repeat booking communication, and pricing strategy. The website pays for itself within the first few direct bookings.',
  'We design holiday let websites around the direct booking conversion funnel. Full-screen property photography and virtual tours create desire. Local area guides establish the destination appeal. A synced availability calendar shows real-time dates. A secure booking system with instant confirmation and integrated payment removes friction. Repeat guest incentives and email capture build a direct booking audience over time.',
  '[{"title": "Platform commission consuming fifteen to twenty percent of revenue", "description": "Every Airbnb and Booking.com reservation costs you a significant percentage in commission fees. For a popular Kent holiday let generating forty to sixty thousand pounds annually, this represents six to twelve thousand pounds per year paid to platforms for bookings that a direct website could capture commission-free. Without a professional direct booking alternative, you remain permanently dependent on these intermediaries."}, {"title": "No professional online presence beyond platform listings", "description": "Guests who find your property on Airbnb and want to verify it is legitimate search for your property name or business online. If they find nothing, or find a basic template website with stock photography and no personality, their confidence drops. If they find a competing platform listing at a different price, you risk losing the booking to a channel you cannot control."}, {"title": "No mechanism for repeat guest booking outside of platforms", "description": "Guests who loved their stay at your Kent holiday cottage have no easy way to rebook directly. They return to Airbnb, pay the service fee again, and you pay commission again on a guest you have already acquired. Without a direct booking website with repeat guest incentives, you pay acquisition costs repeatedly for guests who would happily book direct if given a simple way to do so."}]',
  '[{"title": "Full-screen property showcase with virtual tours", "description": "Professional photography displayed in immersive full-screen galleries, with room-by-room virtual tours that let guests explore your property before booking. Detailed descriptions of each room, the garden or outdoor space, parking arrangements, and unique features like sea views, wood burners, or hot tubs give guests the confidence to book directly rather than through a platform where your listing competes with hundreds of alternatives."}, {"title": "Real-time availability calendar with direct booking integration", "description": "An availability calendar synced with your channel manager showing real-time open dates across all platforms. A secure booking system processes direct reservations with instant confirmation and integrated Stripe or PayPal payment. Guests experience a booking process as smooth as Airbnb but without the service fees, making direct booking the obvious choice for informed travellers."}, {"title": "Local area guides that sell the destination and boost SEO", "description": "Comprehensive guides to the local area around your property: nearest beaches and coastal walks, historic towns and villages, restaurants and pubs, family activities, and seasonal events. These pages serve dual purposes: they excite potential guests about the destination, and they capture organic search traffic from travellers researching Kent holidays who discover your property through the area content."}]',
  '[{"question": "Can a direct booking website really reduce my Airbnb dependency?", "answer": "Yes. Most holiday let owners we work with shift twenty to forty percent of their bookings to direct within the first year. Repeat guests convert first because they already trust you. New guests find you through Google searches, social media, and local area content. Even shifting a third of bookings from platforms to direct on a forty-thousand-pound property saves four to six thousand pounds annually in commission."}, {"question": "How does the availability calendar sync with my existing channels?", "answer": "We integrate with popular channel managers like Guesty, Hospitable, Lodgify, and Your.Rentals. When a booking is made on any platform or directly through your website, all calendars update in real time. This prevents double bookings and ensures guests always see accurate availability regardless of which channel they are viewing."}, {"question": "Will guests trust booking directly rather than through Airbnb?", "answer": "When your website looks professional, displays genuine guest reviews, provides a secure payment process, and clearly shows your business credentials, guests are happy to book directly because they save on Airbnb service fees. Many seasoned holiday guests actively prefer direct booking for the personal relationship, flexibility, and cost savings it provides."}, {"question": "How long does a holiday let website take to build?", "answer": "Most holiday let websites launch within four to six weeks. The timeline depends on photography availability and the number of local area guide pages included at launch. We can work with existing professional photos if you have them, or coordinate with our photography partners for property shoots that capture your holiday let at its best."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 2. Holiday Lets x SEO
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'holiday-lets',
  'seo',
  'When a family searches for holiday cottage Kent coast or dog-friendly holiday let Canterbury, the properties and booking platforms that appear on the first page of Google receive the overwhelming majority of clicks and bookings. Airbnb, Booking.com, and Vrbo dominate many holiday accommodation search terms through massive SEO investment, but there is significant opportunity for individual holiday let owners to rank for specific, high-intent search phrases that platforms cannot target as effectively. Searches like cosy cottage near Whitstable harbour, family holiday home near Canterbury with garden, or romantic retreat Kent countryside with hot tub are specific enough that a well-optimised individual property website can outrank platforms. Our SEO campaigns for holiday lets focus on these specific property-plus-destination combinations alongside local area content that captures travellers researching Kent holidays. By ranking for destination-specific terms and local activity searches, your website becomes a discovery channel that attracts guests who might never have found you on a crowded platform listing page.',
  'Holiday let bookings from organic search are commission-free, making every SEO-generated booking significantly more profitable than a platform booking. A family finding your dog-friendly cottage through a Google search for pet-friendly holiday home Whitstable and booking directly represents the full nightly rate with zero commission deducted. Over time, SEO creates a self-sustaining direct booking channel that reduces your dependency on platforms and their rising commission structures.',
  'Holiday let SEO targets two distinct search intents: guests searching for specific accommodation types in specific Kent locations, and travellers researching destinations who discover your property through local area content. We build content for both: property-focused pages targeting accommodation search terms and comprehensive destination guides that capture travellers earlier in their planning journey.',
  '[{"title": "Airbnb and Booking.com dominating holiday accommodation searches", "description": "Platform giants invest millions in SEO to rank for virtually every holiday accommodation search term. Holiday cottage Kent, seaside rental Whitstable, and family holiday home Canterbury all show platform listings dominating the first page. Without a deliberate SEO strategy targeting the specific, long-tail terms that platforms cannot address individually, your direct booking website is invisible to organically searching travellers."}, {"title": "No visibility for destination-specific searches", "description": "Travellers planning a Kent holiday search for things to do near Whitstable, best beaches in Thanet, and family days out Canterbury. Without local area content on your website, you miss the opportunity to capture these destination researchers and introduce your property as accommodation for their planned visit. Platforms cannot create genuinely local destination content the way a Kent-based property owner can."}, {"title": "Seasonal search peaks going uncaptured", "description": "Holiday accommodation searches surge in January when families plan summer holidays, in spring for Easter and half-term breaks, and in late summer for autumn retreats. Without established SEO rankings before these seasonal peaks, your website cannot capture the surge in demand when it matters most. Rankings take months to build, so reactive approaches always miss the booking window."}]',
  '[{"title": "Property-specific pages targeting accommodation search terms", "description": "We create optimised pages targeting the specific search phrases that match your property: dog-friendly holiday cottage Whitstable, romantic retreat Canterbury with hot tub, family holiday home Kent coast, and luxury barn conversion countryside Kent. Each page highlights the features that match the search intent and drives visitors toward the direct booking system."}, {"title": "Comprehensive local area guides capturing destination searches", "description": "In-depth guides covering everything travellers search for when planning a Kent holiday: best beaches in Thanet, walking routes from your property, family activities near Canterbury, restaurant guides for Whitstable and surrounding areas, and seasonal events across Kent. Each guide naturally introduces your property as the ideal base for exploring these attractions."}, {"title": "Seasonal content calendar aligned to booking planning cycles", "description": "Content published months ahead of peak search periods: summer holiday guides in January when families start planning, Easter break content in November, autumn retreat articles in July, and Christmas getaway content in September. This lead time ensures your pages are ranking when search demand peaks, capturing direct bookings during the most lucrative planning windows."}]',
  '[{"question": "Can a single holiday let website really rank against Airbnb?", "answer": "For specific, long-tail search terms, absolutely. Airbnb cannot create a dedicated page for dog-friendly cottage near Whitstable harbour with sea views the way your property website can. We target these specific, high-intent phrases where individual properties can outrank platforms. Combined with destination content that platforms cannot replicate, your website captures travellers through searches that platform listings miss."}, {"question": "How important is local area content for holiday let SEO?", "answer": "Extremely important. Travellers searching for things to do in Whitstable or best walks near Canterbury are actively planning a visit to your area. Comprehensive destination content that answers these queries captures them early in the planning process and introduces your property as accommodation for their trip. This destination discovery approach generates bookings from travellers who were not initially searching for accommodation."}, {"question": "How long before SEO generates direct bookings?", "answer": "Specific property-plus-location terms often show ranking improvements within eight to twelve weeks. Broader destination content takes longer to build authority but creates a sustained traffic source. Most holiday let owners see measurable direct booking increases within four to six months. The cumulative effect builds over time as more content ranks and more travellers discover your property through organic search."}, {"question": "Should I create separate pages for each season?", "answer": "Yes. Travellers searching for Kent summer holiday cottage have different expectations than those searching for cosy winter retreat Kent. Seasonal pages highlight the relevant features of your property and the seasonal attractions of your area. A summer page emphasises outdoor space, beach proximity, and garden features. A winter page highlights wood burners, cosy interiors, and festive local events."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
