-- 3. Holiday Lets x Lead Capture
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'holiday-lets',
  'lead-capture',
  'Holiday let bookings have a long consideration phase. A family planning their summer holiday might research properties in January, shortlist in February, and book in March. During this extended research period, they visit dozens of property websites, compare locations, check reviews, and gradually narrow their options. Without a lead capture system, the visitors who browse your property gallery, check your availability calendar, and read your local area guides but are not ready to book today disappear forever. You have no way to follow up, no way to remind them of your property when they reach their booking decision, and no way to offer them an incentive to book direct rather than returning to Airbnb. Lead capture for holiday lets creates multiple touchpoints to engage browsing travellers: downloadable area guides that exchange local insider knowledge for an email address, availability alert sign-ups that notify interested guests when their preferred dates become available, and early-bird seasonal offers that reward planning-stage travellers who commit to your email list.',
  'The average holiday let website visitor views four to six pages, spends several minutes browsing photos and checking availability, and then leaves without booking or making contact. They continue researching other properties and often forget your listing entirely by the time they are ready to commit. Without capturing their email address during the research phase, you cannot re-engage them when they reach the booking decision point.',
  'We build holiday let lead capture around the traveller research journey. Local area guides and insider tips exchange genuine destination value for email addresses. Availability alert systems capture interest in specific date ranges. Seasonal offer campaigns reach planning-stage travellers early. Repeat guest nurture sequences keep your property front of mind for previous visitors who have not yet rebooked.',
  '[{"title": "Website visitors browsing extensively then disappearing", "description": "Travellers spend significant time on your website during the holiday research phase: browsing every room photo, reading local area guides, and checking availability across multiple weekends. Then they leave to compare other properties. Without capturing their email address during this engaged browsing session, you have no way to re-engage them when they are ready to book, and they often return to Airbnb where your listing is one among hundreds."}, {"title": "No mechanism to notify interested guests when dates become available", "description": "A traveller checks your availability for August bank holiday weekend and finds it booked. They are genuinely interested in your property but cannot find open dates that work for them. Without an availability alert system, they move on to other properties. When a cancellation opens up your August bank holiday, the interested guest never knows and the dates go to whoever happens to check next."}, {"title": "No email database for direct marketing and repeat bookings", "description": "Without lead capture, every booking requires fresh acquisition through platforms or search. You have no database of interested travellers to market seasonal offers to, no list of previous guests to prompt for repeat bookings, and no audience for last-minute availability promotions. Each booking cycle starts from zero rather than building on an accumulated audience of warm prospects."}]',
  '[{"title": "Downloadable local area guides as lead magnets", "description": "Beautifully designed PDF guides offering genuine insider knowledge: The Local''s Guide to Whitstable, Hidden Beaches of the Kent Coast, or Family Days Out Within Thirty Minutes of Your Property. Travellers researching their Kent holiday provide their email address to download these genuinely useful guides, giving you permission to follow up with property availability updates and seasonal offers throughout their planning process."}, {"title": "Availability alert and wishlist system", "description": "Travellers who cannot find suitable open dates can sign up for availability alerts for their preferred date ranges. When a cancellation creates an opening, automatic notifications reach interested guests immediately. A property wishlist feature allows undecided travellers to save your property and receive a reminder sequence that re-engages them during the booking decision window."}, {"title": "Seasonal and early-bird offer campaigns to captured leads", "description": "Email campaigns targeting your captured lead database with seasonal booking offers: early-bird summer discounts for those booking before March, autumn retreat packages highlighting harvest festivals and golden beach walks, winter getaway offers featuring cosy features and Christmas markets. These campaigns convert planning-stage researchers into confirmed bookings before they return to platforms."}]',
  '[{"question": "What makes someone download an area guide instead of just browsing online?", "answer": "The guides offer curated, insider knowledge that travellers cannot easily assemble from generic travel sites: specific restaurant recommendations with booking tips, the best beach for families versus couples, walks that start from your property door, and seasonal events worth timing a visit around. This exclusive, local-expert content provides genuine value that justifies sharing an email address."}, {"question": "How does the availability alert system work?", "answer": "When a traveller searches your calendar and finds their preferred dates booked, a prompt invites them to enter their email and date preferences. When a cancellation opens matching dates, an automated email notifies them immediately with a direct booking link. This captures demand that would otherwise be lost and fills cancellation gaps faster than relying on platform algorithms."}, {"question": "How do I nurture leads without being annoying?", "answer": "Our email sequences are designed around genuine value: local event updates, seasonal destination highlights, and exclusive early-access to booking dates. Emails are sent at natural planning intervals, not weekly spam. A traveller who downloaded your summer guide in January receives follow-ups in February with early booking incentives and in March with availability updates, aligned to their natural planning timeline."}, {"question": "Can lead capture help increase repeat bookings from past guests?", "answer": "Absolutely. Past guest email addresses feed into a dedicated repeat guest programme: annual booking reminders timed to when they stayed last year, early access to their preferred dates before general availability opens, and loyalty discounts that reward returning guests. This repeat guest nurture system is one of the highest-value lead capture applications because past guests already trust your property and book with minimal marketing effort."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
