-- 4. Holiday Lets x Business Automation
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'holiday-lets',
  'business-automation',
  'Managing a holiday let involves a complex sequence of operations for every booking: confirming the reservation, collecting payment, sending pre-arrival information with check-in instructions and key safe codes, coordinating cleaning turnarounds between guests, sending mid-stay check-in messages, providing local recommendations, collecting post-departure reviews, processing security deposit returns, and updating availability across all listing platforms. For a property with fifty to one hundred bookings per year, this operational cycle repeats constantly, and every missed step affects the guest experience or your review rating. Business automation for holiday lets systematises the entire guest journey from booking confirmation to post-departure review request. Pre-arrival emails are sent automatically at the right intervals with property-specific check-in instructions, WiFi passwords, parking details, and local area recommendations. Cleaning teams receive automated turnover notifications with the next guest''s arrival time. Mid-stay messages check guest satisfaction without requiring your personal intervention. Post-departure sequences request reviews, return deposits, and capture repeat booking interest.',
  'A five-star guest experience requires consistent, timely communication at every stage of the booking journey. Manually sending check-in instructions, coordinating cleaners, and chasing reviews for every one of fifty to one hundred annual bookings is unsustainable. Missed communications damage reviews, forgotten cleaner notifications cause turnover chaos, and neglected review requests leave your listing without the social proof that drives future bookings.',
  'Holiday let automation follows the guest journey timeline. Booking confirmation triggers a sequenced communication chain: payment collection, pre-arrival information at seven days and one day before check-in, check-in day welcome messages, mid-stay satisfaction check, pre-departure reminders, and post-departure review requests. Cleaning team notifications are triggered by check-out dates with turnaround time calculations.',
  '[{"title": "Pre-arrival information sent inconsistently or forgotten entirely", "description": "Check-in instructions, key safe codes, WiFi passwords, and parking details need reaching guests before arrival. When you manage this manually across fifty bookings per year, messages are sent at inconsistent times: sometimes a week early, sometimes the morning of arrival when the guest is already driving. Inconsistent pre-arrival communication creates anxious guests who arrive stressed rather than excited."}, {"title": "Cleaning turnaround coordination causing missed changeovers", "description": "When a Saturday checkout at eleven is followed by a Saturday check-in at four, your cleaning team has a five-hour window to turn the property around. If the cleaner is not notified in time, or if the previous guest checks out late without anyone knowing, the next guest arrives to a property that is not ready. These turnaround failures generate the most damaging reviews a holiday let can receive."}, {"title": "Post-departure review collection happening inconsistently", "description": "Reviews are the lifeblood of holiday let bookings. Yet requesting reviews requires sending a perfectly timed message to each departing guest while you are simultaneously preparing for the next arrival. Without automation, review requests are forgotten, sent too late, or skipped entirely during busy changeover periods. Every missed review is a missed opportunity to build the social proof that drives future bookings."}]',
  '[{"title": "Automated guest journey from booking to post-departure", "description": "Every booking triggers a sequenced communication chain: immediate booking confirmation, payment collection, pre-arrival information at seven days with property guide and local recommendations, one-day-before reminder with check-in instructions and key safe code, check-in day welcome message, mid-stay satisfaction check, pre-departure checkout reminders, and post-departure review request and repeat booking offer. Every guest receives consistent, professional communication without your manual involvement."}, {"title": "Cleaning team turnover notifications with gap calculations", "description": "When a booking is confirmed, the system calculates the turnaround window between check-out and next check-in, notifies your cleaning team with the specific property, date, check-out time, and next arrival time, and sends reminders on the turnaround morning. If a guest requests late checkout, the system alerts the cleaner to the adjusted schedule. No turnaround is ever missed because of a communication gap."}, {"title": "Review collection and repeat booking nurture sequences", "description": "Two days after departure, guests receive a personalised review request with direct links to leave feedback on your preferred platform. The message references specific features of their stay to prompt detailed, positive reviews. A follow-up sequence offers a repeat guest discount for future bookings and invites them to join your direct booking mailing list, converting platform guests into future direct bookers."}]',
  '[{"question": "Can automation handle different check-in instructions for different booking platforms?", "answer": "Yes. The system recognises whether a booking came through Airbnb, Booking.com, or direct, and adjusts communication accordingly. Platform bookings receive check-in instructions through the platform messaging system as required by their terms. Direct bookings receive communications via email and SMS. The content is consistent, but the delivery channel adapts to each booking source."}, {"question": "How does the cleaning team notification system work?", "answer": "When a booking is confirmed, the system calculates the changeover window and sends your cleaner a notification with the property name, checkout date and time, next guest arrival date and time, and any special preparation notes. A reminder is sent the morning of the turnaround. If the turnaround window changes due to early check-in requests or late checkouts, the cleaner is automatically updated."}, {"question": "Can the system handle multi-property holiday let portfolios?", "answer": "Yes. The automation scales to manage multiple properties, each with their own check-in instructions, cleaning teams, and communication templates. A portfolio dashboard shows upcoming arrivals, departures, and turnarounds across all properties. Each property has its own automated guest journey while you maintain oversight of the entire portfolio from a single view."}, {"question": "How does the review request system work?", "answer": "Two days after checkout, guests receive a friendly email thanking them for their stay and linking directly to the review platform where their feedback has the most impact. The message is personalised with the property name and dates of their stay. A gentle reminder follows five days later if they have not yet left a review. This consistent, well-timed approach typically doubles the review rate compared to manual requests."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
