-- 6. Holiday Lets x Social Media Setup
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'holiday-lets',
  'social-media-setup',
  'Social media is one of the most powerful marketing channels for holiday lets because travel is inherently visual, aspirational, and shareable. A stunning sunset viewed from your property''s terrace, a cosy fireside scene on a winter evening, a family enjoying your garden on a summer morning, or a perfectly styled breakfast table overlooking the harbour are exactly the content that inspires travel planning on Instagram and Facebook. Holiday let social media builds an audience of potential guests who follow your property for the lifestyle it represents, not just the accommodation it provides. When they see your content regularly, your property becomes their mental bookmark for a Kent getaway. We set up and optimise your Instagram and Facebook profiles specifically for holiday let marketing, create content strategies that balance property showcasing with destination promotion, establish a posting rhythm that maintains engagement between peak booking seasons, and build systems for amplifying guest reviews, sharing user-generated content from guest stays, and promoting seasonal availability and offers.',
  'Holiday letting is seasonal, and social media bridges the gap between booking seasons. A property that only markets during peak periods misses the off-season dreaming phase when travellers are planning future trips. Consistent social presence keeps your property visible during these planning phases, so when guests are ready to book, your property is already familiar and trusted rather than a discovery among hundreds of competing listings.',
  'We set up holiday let profiles optimised for destination discovery and direct booking conversion. Instagram grids are planned for visual cohesion. Facebook pages are configured for local event sharing and guest review amplification. Content templates cover property styling shots, seasonal destination highlights, guest review features, and behind-the-scenes hosting content. Booking links are integrated into every profile touchpoint.',
  '[{"title": "Beautiful property content going unshared beyond listing platforms", "description": "Your holiday let produces naturally stunning content across every season: golden morning light in the bedroom, harbour views from the terrace, a roaring fire on a winter evening, wildflowers in the garden in spring. Without social media, this aspirational content lives only in your listing photos, seen only by travellers who have already found you on a platform. Social media puts this content in front of thousands of potential guests who have not yet started searching."}, {"title": "No guest review amplification beyond platform listings", "description": "Guests leave wonderful reviews about their stay, but these reviews sit on Airbnb where they are only visible to travellers actively browsing your listing. Without social media to share and amplify these testimonials, the powerful social proof of genuine guest experiences reaches only a fraction of its potential audience. Guest reviews shared on social media influence followers who may not have been actively searching."}, {"title": "No seasonal promotion strategy for off-peak periods", "description": "Many holiday lets achieve strong summer occupancy but struggle with autumn, winter, and spring bookings. Without social content promoting off-season experiences: autumn coastal walks, cosy winter retreats, spring garden blooming, and festive market weekends, your property is invisible during the planning phase for these valuable shoulder-season bookings."}]',
  '[{"title": "Instagram-optimised property and destination showcase", "description": "We set up your Instagram with a cohesive grid aesthetic that alternates between property interior styling, destination landscape and activity photography, guest experience moments, and seasonal promotional content. Highlight reels showcase individual rooms, the local area, guest reviews, and seasonal experiences. The feed functions as a visual catalogue that makes travellers save your profile for future booking."}, {"title": "Guest review amplification and user-generated content system", "description": "Branded templates transform guest reviews into shareable social posts with property photography backgrounds. A system for encouraging and collecting guest Instagram photos and stories creates a stream of authentic user-generated content. Reposting guest content builds community, provides social proof, and generates authentic marketing that platform-owned reviews cannot replicate."}, {"title": "Seasonal and promotional content calendar", "description": "A year-round content calendar aligned to booking planning cycles: winter cosiness content in September for autumn and winter bookings, spring destination highlights in January for Easter breaks, summer lifestyle content from March onwards for peak season bookings. Last-minute availability posts, seasonal offers, and event-based promotions fill gaps in the calendar and drive bookings during off-peak periods."}]',
  '[{"question": "Should a holiday let focus on Instagram or Facebook?", "answer": "Both serve different purposes. Instagram is the primary platform for aspirational property and destination content that builds a following of future guests. Facebook excels at local event sharing, guest review amplification, community group engagement, and direct offer promotion. We set up both platforms but invest more creative effort in Instagram for its visual storytelling power and travel-planning influence."}, {"question": "How do I get guests to share photos of their stay?", "answer": "Create photographable moments: a styled welcome hamper, a breakfast tray with a view, a branded guest information booklet in a photogenic spot, and a property sign that makes for a good arrival photo. Include your Instagram handle on the welcome materials with a gentle prompt to share their experience. Most guests, especially younger demographics, naturally share attractive holiday moments when the opportunity is created for them."}, {"question": "How often should a holiday let post on social media?", "answer": "Three to four posts per week on Instagram and two to three on Facebook maintains strong visibility. Content types rotate between property interior styling, local destination highlights, guest reviews, seasonal activities, and availability promotions. During peak booking planning periods, posting frequency can increase with offer content and seasonal showcasing."}, {"question": "Can social media help fill off-season availability?", "answer": "This is one of social media''s strongest applications for holiday lets. Visual content showing your property in autumn golden light, winter cosiness with a log burner, or spring garden displays creates desire for off-season stays that travellers may not have considered. Seasonal promotion posts with off-peak pricing and weekend break offers convert social followers into shoulder-season bookings."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
