  faqs = EXCLUDED.faqs;

-- 7. Holiday Lets x Digital Marketing
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'holiday-lets',
  'digital-marketing',
  'Digital marketing for holiday lets operates within a unique commercial model: every direct booking saves fifteen to twenty percent in platform commission, making the return on marketing investment dramatically higher than for most businesses. A Google Ads campaign that generates a one-thousand-pound direct booking saves you one hundred and fifty to two hundred pounds in commission that would have gone to Airbnb or Booking.com. This commission saving means holiday let digital marketing pays for itself at lower conversion rates than almost any other industry. Our approach coordinates multiple channels to build a direct booking pipeline: Google Ads targeting travellers searching for specific accommodation in your area, social media campaigns building aspirational audiences who convert during planning phases, retargeting campaigns keeping your property visible to website visitors who browsed but did not book, email campaigns to your subscriber list promoting seasonal availability and special offers, and meta-search presence on Google Hotels ensuring your direct rate is visible alongside platform listings.',
  'Platform commission is the single largest controllable cost in holiday let ownership. Shifting even a modest proportion of bookings from platforms to direct channels saves thousands of pounds annually. Digital marketing enables this shift by building awareness, capturing interest, and converting bookings through your own website where you retain the full nightly rate. Every marketing pound spent to generate a direct booking delivers double value: the booking revenue plus the commission saved.',
  'Holiday let marketing requires seasonal budget allocation aligned to booking planning cycles. Summer holidays are researched in January through March, requiring marketing investment months ahead. Shoulder-season campaigns run earlier to capture travellers who have not yet considered off-peak breaks. Retargeting campaigns maintain visibility during the long consideration window between initial research and booking commitment.',
  '[{"title": "Marketing spend failing to account for commission savings", "description": "Many holiday let owners consider marketing an additional cost without factoring in the commission saved on every direct booking. A marketing campaign costing five hundred pounds per month that generates three direct bookings worth one thousand pounds each does not just produce three thousand in revenue. It also saves four hundred and fifty to six hundred pounds in platform commission, making the effective cost of marketing almost zero."}, {"title": "No retargeting for travellers who viewed the property but did not book", "description": "A family visits your website, browses every room photo, checks August availability, and leaves to compare other options. Without retargeting, they see competitor properties advertised during their weeks-long research process while your property disappears from their awareness. The family eventually books a similar property because it was the one they kept seeing during their planning phase."}, {"title": "No presence on Google Hotels meta-search for direct rate visibility", "description": "When travellers search for accommodation on Google, a Google Hotels panel often appears showing pricing from multiple booking channels. If your direct booking website is not listed alongside Airbnb and Booking.com prices, travellers have no way to discover that booking direct is cheaper. Your best direct rate is invisible at the exact moment the traveller is comparing booking options."}]',
  '[{"title": "Commission-aware Google Ads campaigns targeting accommodation searches", "description": "Google Ads campaigns targeting holiday cottage Kent, dog-friendly rental Whitstable, and family holiday home Canterbury with landing pages optimised for direct booking. Campaign performance is measured not just on booking revenue but on total value including commission saved. A direct booking generated for fifty pounds in ad spend that saves one hundred and fifty in commission represents a net positive return even before accounting for the booking revenue itself."}, {"title": "Aspirational social media campaigns with retargeting integration", "description": "Facebook and Instagram campaigns showcasing your property and destination to travel-interested audiences in your target guest demographics. Website visitors who do not immediately book are retargeted across social platforms with seasonal property content, guest reviews, and availability reminders. This persistent visibility during the long holiday planning cycle keeps your property in consideration until the booking decision is made."}, {"title": "Google Hotels integration for direct rate visibility", "description": "We ensure your direct booking rate appears on Google Hotels alongside Airbnb and Booking.com listings, showing travellers that booking direct saves them the platform service fee. When a traveller sees your property on Google, they can compare the platform price against your direct rate and click through to your website to book at the better price. This captures price-conscious travellers at the point of booking decision."}]',
  '[{"question": "How much should a holiday let spend on digital marketing?", "answer": "Most holiday lets see strong returns from three hundred to eight hundred pounds per month, varying seasonally. The commission-saving model means the effective cost is significantly lower than the headline spend. A property earning forty thousand pounds annually that shifts ten bookings from platforms to direct through marketing saves three to four thousand in commission, often exceeding the total annual marketing investment."}, {"question": "When should marketing spend increase for seasonal bookings?", "answer": "Summer holiday marketing should begin in January when families start planning. Easter and half-term campaigns launch eight to ten weeks before the break. Autumn and winter break marketing runs from July onwards. Marketing spend peaks during these planning windows, not during the stays themselves. Last-minute availability campaigns run closer to the date for filling remaining gaps."}, {"question": "How does retargeting work for holiday let bookings?", "answer": "When a traveller visits your website, a tracking pixel records their visit. Over the following weeks, they see your property advertised on Facebook, Instagram, and across the Google Display Network. The ads showcase different aspects of your property and destination, seasonal content, and availability reminders. This sustained visibility during the planning phase keeps your property front of mind until they are ready to book."}, {"question": "Is Google Hotels effective for holiday let direct bookings?", "answer": "Increasingly so. Travellers searching for accommodation on Google see a Google Hotels panel comparing prices across booking channels. When your direct rate appears alongside and below the platform rates, price-conscious travellers click through to your website. This captures bookings from guests who have already decided to stay in your area and are comparing final pricing options."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
